3	type Item = { type: string };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
6	
7	const BASE_PRICES: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	};
12	
13	const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;
14	
15	const quotePremium = (items: Item[]): number =>
16	  items.reduce((sum, item) => sum + basePriceOf(item), 0) + PROCESSING_FEE;
17	
18	export const runScenario = (input: Scenario): { results: { premium: number }[] } => ({
19	  results: input.steps.map((step) => ({ premium: quotePremium(step.items) })),
20	});
